    /**
     * @method
     * @name zebpay#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see [Spot] https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/public-endpoints.md#get-klinescandlesticks
     * @see [Swap] https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/public-endpoints/market.md#-get-k-lines-ohlcv-data
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.endtime] the latest time in ms to fetch orders for
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                limit = 100; // default is 200
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                Helpers.addElementToObject(request, "interval", this.safeString(this.timeframes, timeframe, timeframe));
            } else
            {
                Helpers.addElementToObject(request, "interval", timeframe);
            }
            if (Helpers.isTrue(Helpers.isTrue(Helpers.GetValue(market, "contract")) && Helpers.isTrue((!Helpers.isEqual(limit, null)))))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
                {
                    Helpers.addElementToObject(request, "startTime", since);
                } else
                {
                    Helpers.addElementToObject(request, "since", since);
                }
            }
            Object until = this.safeInteger2(parameters, "until", "endtime");
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "endTime", until);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("endtime", "until")));
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(until, null)) || Helpers.isTrue(Helpers.isEqual(since, null))))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchOHLCV() requires a both a since and until/endtime parameter for spot markets")) ;
                }
                response = (this.publicSpotGetV2MarketKlines(this.extend(request, parameters))).join();
            } else
            {
                response = (this.publicSwapPostV1MarketKlines(this.extend(request, parameters))).join();
            }
            //
            //             [
            //                 [
            //                     "1670608800000",
            //                     "17071",
            //                     "17073",
            //                     "17027",
            //                     "17055.5",
            //                     "268611",
            //                     "15.74462667"
            //                 ],
            //                 [
            //                     "1670605200000",
            //                     "17071.5",
            //                     "17071.5",
            //                     "17061",
            //                     "17071",
            //                     "4177",
            //                     "0.24469757"
            //                 ],
            //                 [
            //                     "1670601600000",
            //                     "17086.5",
            //                     "17088",
            //                     "16978",
            //                     "17071.5",
            //                     "6356",
            //                     "0.37288112"
            //                 ]
            //             ]
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(data, market, timeframe, since, limit);
        });

    }

