    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchMyTrades
        //
        //     {
        //         "id": "32164924331503616",
        //         "symbol": "LINK_USDT",
        //         "accountType": "SPOT",
        //         "orderId": "32164923987566592",
        //         "side": "SELL",
        //         "type": "MARKET",
        //         "matchRole": "TAKER",
        //         "createTime": 1648635115525,
        //         "price": "11",
        //         "quantity": "0.5",
        //         "amount": "5.5",
        //         "feeCurrency": "USDT",
        //         "feeAmount": "0.007975",
        //         "pageId": "32164924331503616",
        //         "clientOrderId": "myOwnId-321"
        //     }
        //   {
        //     aggregateTradeId: '2659115835',
        //     symbol: 'ETHINR',
        //     price: '292848',
        //     quantity: '0.147',
        //     firstTradeId: '7018766077',
        //     lastTradeId: '7018766081',
        //     tradeTime: '1765381971447',
        //     isBuyerMarketMaker: true
        //   }
        //
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString2(trade, "id", "aggregateTradeId");
        Object orderId = this.safeString2(trade, "id", "order");
        Object timestamp = this.safeInteger2(trade, "timestamp", "tradeTime");
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market, "_");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object side = this.safeStringLower(trade, "side");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString2(trade, "amount", "quantity");
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", ZebpayCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", ZebpayCore.this.safeStringLower(trade, "type") );
            put( "side", side );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", ZebpayCore.this.safeString(trade, "cost") );
            put( "fee", ZebpayCore.this.safeDict(trade, "fee") );
        }}, market);
    }

