    /**
     * @method
     * @name zebpay#createOrder
     * @description Create an order on the exchange
     * @see [Spot] https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#place-new-order
     * @see [Swap] https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/private-endpoints/trade.md#--create-order
     * @param {string} symbol Unified CCXT market symbol
     * @param {string} type 'limit' or 'market'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount the amount of currency to trade
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params]  extra parameters specific to the exchange API endpoint
     * @param {string} [params.formType] The price at which a trigger order is triggered at
     * @param {string} [params.marginAsset] The asset the order creates, default is INR.
     * @param {boolean} [params.takeProfit] Takeprofit flag for the order.
     * @param {boolean} [params.stopLoss] Stop loss flag for the order.
     * @param {string} [params.positionId] PositionId of the order.
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object upperCaseType = ((String)type).toUpperCase();
            Object takeProfitPrice = this.safeString(parameters, "takeProfitPrice");
            Object stopLossPrice = this.safeString(parameters, "stopLossPrice");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("marginAsset", "takeProfitPrice", "takeProfitPrice")));
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "side", ((String)side).toUpperCase() );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                var requestparametersVariable = this.orderRequest(symbol, type, amount, request, price, parameters);
                request = ((java.util.List<Object>) requestparametersVariable).get(0);
                parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
                response = (this.privateSpotPostV2ExOrders(this.extend(request, parameters))).join();
            } else
            {
                Object marginAsset = this.safeString(parameters, "marginAsset", "INR");
                Object formType = this.safeStringUpper(parameters, "formType", "ORDER_FORM");
                Helpers.addElementToObject(request, "formType", formType);
                Helpers.addElementToObject(request, "amount", this.parseToNumeric(this.amountToPrecision(Helpers.GetValue(market, "id"), amount)));
                Helpers.addElementToObject(request, "marginAsset", marginAsset);
                Object hasTP = !Helpers.isEqual(takeProfitPrice, null);
                Object hasSL = !Helpers.isEqual(stopLossPrice, null);
                if (Helpers.isTrue(Helpers.isTrue(hasTP) || Helpers.isTrue(hasSL)))
                {
                    if (Helpers.isTrue(hasTP))
                    {
                        Helpers.addElementToObject(request, "takeProfitPrice", this.parseToNumeric(this.priceToPrecision(symbol, takeProfitPrice)));
                    }
                    if (Helpers.isTrue(hasSL))
                    {
                        Helpers.addElementToObject(request, "stopLossPrice", this.parseToNumeric(this.priceToPrecision(symbol, stopLossPrice)));
                    }
                    response = (this.privateSwapPostV1TradeOrderAddTPSL(this.extend(request, parameters))).join();
                } else
                {
                    Helpers.addElementToObject(request, "type", upperCaseType);
                    if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
                    {
                        if (Helpers.isTrue(Helpers.isEqual(price, null)))
                        {
                            throw new ArgumentsRequired((String)Helpers.add(this.id, " createOrder() requires a price argument for limit orders")) ;
                        }
                        Helpers.addElementToObject(request, "price", this.parseToNumeric(this.priceToPrecision(symbol, price)));
                    }
                    response = (this.privateSwapPostV1TradeOrder(this.extend(request, parameters))).join();
                }
            }
            //
            //    {
            //        "data": {
            //            "clientOrderId": "619717484f1d010001510cde",
            //        },
            //    }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(data, market);
        });

    }

    public Object orderRequest(Object symbol, Object type, Object amount, Object request, Object... optionalArgs)
    {
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object upperCaseType = ((String)type).toUpperCase();
        Object triggerPrice = this.safeString(parameters, "stopLossPrice", null);
        Object quoteOrderQty = this.safeString2(parameters, "quoteOrderQty", "cost", null);
        Object timeInForce = this.safeString(parameters, "timeInForce", "GTC");
        Object clientOrderId = this.safeString(parameters, "clientOrderId", this.uuid());
        parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stopLossPrice", "cost", "timeInForce", "clientOrderId")));
        Helpers.addElementToObject(request, "type", upperCaseType);
        Helpers.addElementToObject(request, "clientOrderId", clientOrderId);
        Helpers.addElementToObject(request, "timeInForce", timeInForce);
        if (Helpers.isTrue(Helpers.isEqual(upperCaseType, "MARKET")))
        {
            if (Helpers.isTrue(Helpers.isEqual(quoteOrderQty, null)))
            {
                throw new ExchangeError((String)Helpers.add(this.id, " spot market orders require cost in params")) ;
            }
            Helpers.addElementToObject(request, "quoteOrderAmount", this.costToPrecision(symbol, quoteOrderQty));
        } else
        {
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                Helpers.addElementToObject(request, "stopLossPrice", this.priceToPrecision(symbol, triggerPrice));
            }
            Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
            Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(request, parameters));
    }

