    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //      {
        //          "clientOrderId": "64507d02921f1c0001ff6892-123-zeb",
        //          "datetime": "2025-03-14T14:34:34.4567",
        //          "timestamp": 1741962557553,
        //          "status": "open",
        //          "symbol": "BTCINR",
        //          "type": "market",
        //          "timeInForce": "GTC",
        //          "side": "buy",
        //          "price": 700000,
        //          "amount": 0.002,
        //          "filled": null,
        //          "remaining": 0.002,
        //          "trades": []
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object type = this.safeString(order, "type");
        Object timestamp = this.safeNumber(order, "timestamp");
        Object datetime = this.iso8601(timestamp);
        Object price = this.safeString(order, "price");
        Object side = this.safeString(order, "side");
        Object amount = this.safeString(order, "amount");
        Object clientOrderId = this.safeString(order, "clientOrderId");
        Object timeInForce = this.safeString(order, "timeInForce");
        Object status = this.safeStringLower(order, "status");
        Object orderId = this.safeString(order, "orderId", null);
        Object parsedOrder = this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "symbol", symbol );
            put( "type", type );
            put( "timeInForce", timeInForce );
            put( "postOnly", null );
            put( "reduceOnly", null );
            put( "side", side );
            put( "amount", amount );
            put( "price", price );
            put( "triggerPrice", null );
            put( "cost", null );
            put( "filled", null );
            put( "remaining", null );
            put( "timestamp", timestamp );
            put( "datetime", datetime );
            put( "fee", null );
            put( "status", status );
            put( "info", order );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", null );
            put( "average", null );
            put( "trades", null );
        }}, market);
        return parsedOrder;
    }

